VALUES
  ('social-worker-moex-07650', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '司法院在民國98年7月31日做出第664號解釋文，認為少年事件處理法部分規定違憲，請問主要是指 那一部分？', '["「對經常逃學或逃家的虞犯少年，裁定收容或令入感化教育」的規定", "「對有觸犯管訓事件之行為少年，裁定收容或令入感化教育」的規定", "「對有觸犯刑事案件之行為少年，裁定收容或令入感化教育」的規定", "「對有觸犯刑罰法律之行為少年，裁定收容或令入感化教育」的規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07651', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '2009 年台北市政府針對壹傳媒「動新聞」開罰，並宣布北市 300 多所國高中小學停止訂閱蘋果日報， 請問台北市是依那一個法令所作的決定？', '["兒童及少年福利法", "社會秩序維護法", "廣播電視法", "通訊傳播基本法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07652', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依照我國「家庭暴力防治法」規定，民事保護令分為：', '["一般保護令、臨時保護令及緊急保護令", "通常保護令、暫時保護令及特別保護令", "通常保護令、暫時保護令及緊急保護令", "一般保護令、暫時保護令及緊急保護令"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07653', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作實務上為防範法律過失（negligence）或專業過失（mal-practice）所引起的訴訟或爭議，故必 須採取社會工作者本身自我保護的考量與做法，乃屬於下列那一種價值傾向？', '["父權主義（paternalistic orientation）", "專業保衛取向（defensive orientation）或臨床倫理（clinical orientation）", "宗教取向（religious orientation）", "去道德或中立（amoralistic orientation）或宗教情懷（religious orientation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07654', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Helen Perlman綜合功能學派和社會診斷學派而提出「問題解決學派」理論，請問此一學派採用杜威實用 主義哲學，在社會工作處遇上的基本假定為何（請選出最適者）？', '["人有解決問題的潛能", "人有達成生活期待、目標與任務的能力", "人有理性的評量、規劃、執行和檢討之認知及行為能力", "以上皆是"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07655', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依照我國「特殊境遇家庭扶助條例」，符合特殊境遇家庭資格規定之家庭，可接受政府提供那些項目', '["緊急生活扶助", "子女生活津貼", "租金補助", "居家服務 ⑤創業貸款補助"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07656', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就系統觀點而言，社會工作者的專業角色，請問乃屬於下列那一個選項（請選出最適者）？', '["資源連結或媒介者", "教育者", "倡導者", "以上皆是"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07657', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Lowenberg and Dolgoff（1992）對社會工作實務的倫理抉擇優先順序之考量，提出七項原則，請問並不包 括下列那一個選項？', '["保護生命與最小傷害", "人情與面子", "生活品質與隱私", "差別平等與自主自由"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
