  ('social-worker-moex-07659', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在處遇目標上，希望在公領域男女機會均等的主張，主要乃屬於女性主義的那一流派觀點？', '["自由派", "激進派", "社會主義派", "後現代派"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "2102dcee2059", "answer_pdf_sha1": "c07017abeea7", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
